// C documentation
//
//	/****************/
//	/* Decode frame */
//	/****************/
func SKP_Silk_decode_frame(tls *libc.TLS, psDec uintptr, pOut uintptr, pN uintptr, pCode uintptr, nBytes int32, action int32, decBytes uintptr) (r int32) {
	bp := tls.Alloc(2096)
	defer tls.Free(2096)
	var L, fs_Khz_old, ret int32
	var _ /* Pulses at bp+164 */ [480]int32
	var _ /* sDecCtrl at bp+0 */ SKP_Silk_decoder_control
	_, _, _ = L, fs_Khz_old, ret
	ret = 0
	L = (*SKP_Silk_decoder_state)(unsafe.Pointer(psDec)).Fframe_length
	(*(*SKP_Silk_decoder_control)(unsafe.Pointer(bp))).FLTP_scale_Q14 = 0
	/* Safety checks */
	/********************************************/
	/* Decode Frame if packet is not lost  */
	/********************************************/
	*(*int32)(unsafe.Pointer(decBytes)) = 0
	if action == 0 {
		/********************************************/
		/* Initialize arithmetic coder              */
		/********************************************/
		fs_Khz_old = (*SKP_Silk_decoder_state)(unsafe.Pointer(psDec)).Ffs_kHz
		if (*SKP_Silk_decoder_state)(unsafe.Pointer(psDec)).FnFramesDecoded == 0 {
			/* Initialize range decoder state */
			SKP_Silk_range_dec_init(tls, psDec, pCode, nBytes)
		}
		/********************************************/
		/* Decode parameters and pulse signal       */
		/********************************************/
		SKP_Silk_decode_parameters(tls, psDec, bp, bp+164, int32(1))
		if (*SKP_Silk_decoder_state)(unsafe.Pointer(psDec)).FsRC.Ferror1 != 0 {
			(*SKP_Silk_decoder_state)(unsafe.Pointer(psDec)).FnBytesLeft = 0
			action = int32(1) /* PLC operation */
			/* revert fs if changed in decode_parameters */
			SKP_Silk_decoder_set_fs(tls, psDec, fs_Khz_old)
			/* Avoid crashing */
			*(*int32)(unsafe.Pointer(decBytes)) = (*SKP_Silk_decoder_state)(unsafe.Pointer(psDec)).FsRC.FbufferLength
			if (*SKP_Silk_decoder_state)(unsafe.Pointer(psDec)).FsRC.Ferror1 == -int32(8) {
				ret = -int32(11)
			} else {
				ret = -int32(12)
			}
		} else {
			*(*int32)(unsafe.Pointer(decBytes)) = (*SKP_Silk_decoder_state)(unsafe.Pointer(psDec)).FsRC.FbufferLength - (*SKP_Silk_decoder_state)(unsafe.Pointer(psDec)).FnBytesLeft
			(*SKP_Silk_decoder_state)(unsafe.Pointer(psDec)).FnFramesDecoded = (*SKP_Silk_decoder_state)(unsafe.Pointer(psDec)).FnFramesDecoded + 1
			/* Update lengths. Sampling frequency could have changed */
			L = (*SKP_Silk_decoder_state)(unsafe.Pointer(psDec)).Fframe_length
			/********************************************************/
			/* Run inverse NSQ                                      */
			/********************************************************/
			SKP_Silk_decode_core(tls, psDec, bp, pOut, bp+164)
			/********************************************************/
			/* Update PLC state                                     */
			/********************************************************/
			SKP_Silk_PLC(tls, psDec, bp, pOut, L, action)
			(*SKP_Silk_decoder_state)(unsafe.Pointer(psDec)).FlossCnt = 0
			(*SKP_Silk_decoder_state)(unsafe.Pointer(psDec)).Fprev_sigtype = (*(*SKP_Silk_decoder_control)(unsafe.Pointer(bp))).Fsigtype
			/* A frame has been decoded without errors */
			(*SKP_Silk_decoder_state)(unsafe.Pointer(psDec)).Ffirst_frame_after_reset = 0
		}
	}
	/*************************************************************/
	/* Generate Concealment frame if packet is lost, or corrupt  */
	/*************************************************************/
	if action == int32(1) {
		/* Handle packet loss by extrapolation */
		SKP_Silk_PLC(tls, psDec, bp, pOut, L, action)
	}
	/*************************/
	/* Update output buffer. */
	/*************************/
	libc.Xmemcpy(tls, psDec+9272, pOut, libc.Uint64FromInt32(L)*libc.Uint64FromInt64(2))
	/****************************************************************/
	/* Ensure smooth connection of extrapolated and good frames     */
	/****************************************************************/
	SKP_Silk_PLC_glue_frames(tls, psDec, bp, pOut, L)
	/************************************************/
	/* Comfort noise generation / estimation        */
	/************************************************/
	SKP_Silk_CNG(tls, psDec, bp, pOut, L)
	/********************************************/
	/* HP filter output                            */
	/********************************************/
	SKP_Silk_biquad(tls, pOut, (*SKP_Silk_decoder_state)(unsafe.Pointer(psDec)).FHP_B, (*SKP_Silk_decoder_state)(unsafe.Pointer(psDec)).FHP_A, psDec+11208, pOut, L)
	/********************************************/
	/* set output frame length                    */
	/********************************************/
	*(*int16)(unsafe.Pointer(pN)) = int16(L)
	/* Update some decoder state variables */
	(*SKP_Silk_decoder_state)(unsafe.Pointer(psDec)).FlagPrev = *(*int32)(unsafe.Pointer(bp + uintptr(libc.Int32FromInt32(NB_SUBFR)-libc.Int32FromInt32(1))*4))
	return ret
}

