			*(*int32)(unsafe.Pointer(pitch_lags + uintptr(i)*4)) = lag + int32(*(*int16)(unsafe.Pointer(uintptr(unsafe.Pointer(&SKP_Silk_CB_lags_stage3)) + uintptr(i)*68 + uintptr(contourIndex)*2)))
			goto _2
