	/***************************************************/
	cdf_ptr = uintptr(unsafe.Pointer(&SKP_Silk_pulses_per_block_CDF)) + uintptr((*SKP_Silk_decoder_control)(unsafe.Pointer(psDecCtrl)).FRateLevelIndex)*42
