// C documentation
//
//	/* Set decoder sampling rate */
func SKP_Silk_decoder_set_fs(tls *libc.TLS, psDec uintptr, fs_kHz int32) {
	if (*SKP_Silk_decoder_state)(unsafe.Pointer(psDec)).Ffs_kHz != fs_kHz {
		(*SKP_Silk_decoder_state)(unsafe.Pointer(psDec)).Ffs_kHz = fs_kHz
		(*SKP_Silk_decoder_state)(unsafe.Pointer(psDec)).Fframe_length = int32(int16(libc.Int32FromInt32(FRAME_LENGTH_MS))) * int32(int16(fs_kHz))
		(*SKP_Silk_decoder_state)(unsafe.Pointer(psDec)).Fsubfr_length = int32(int16(libc.Int32FromInt32(FRAME_LENGTH_MS)/libc.Int32FromInt32(NB_SUBFR))) * int32(int16(fs_kHz))
		if (*SKP_Silk_decoder_state)(unsafe.Pointer(psDec)).Ffs_kHz == int32(8) {
			(*SKP_Silk_decoder_state)(unsafe.Pointer(psDec)).FLPC_order = int32(MIN_LPC_ORDER)
			*(*uintptr)(unsafe.Pointer(psDec + 11536)) = uintptr(unsafe.Pointer(&SKP_Silk_NLSF_CB0_10))
			*(*uintptr)(unsafe.Pointer(psDec + 11536 + 1*8)) = uintptr(unsafe.Pointer(&SKP_Silk_NLSF_CB1_10))
		} else {
			(*SKP_Silk_decoder_state)(unsafe.Pointer(psDec)).FLPC_order = int32(MAX_LPC_ORDER)
			*(*uintptr)(unsafe.Pointer(psDec + 11536)) = uintptr(unsafe.Pointer(&SKP_Silk_NLSF_CB0_16))
			*(*uintptr)(unsafe.Pointer(psDec + 11536 + 1*8)) = uintptr(unsafe.Pointer(&SKP_Silk_NLSF_CB1_16))
		}
		/* Reset part of the decoder state */
		libc.Xmemset(tls, psDec+4888, 0, libc.Uint64FromInt32(MAX_LPC_ORDER)*libc.Uint64FromInt64(4))
		libc.Xmemset(tls, psDec+9272, 0, libc.Uint64FromInt32(libc.Int32FromInt32(FRAME_LENGTH_MS)*libc.Int32FromInt32(MAX_FS_KHZ))*libc.Uint64FromInt64(2))
		libc.Xmemset(tls, psDec+11252, 0, libc.Uint64FromInt32(MAX_LPC_ORDER)*libc.Uint64FromInt64(4))
		(*SKP_Silk_decoder_state)(unsafe.Pointer(psDec)).FlagPrev = int32(100)
		(*SKP_Silk_decoder_state)(unsafe.Pointer(psDec)).FLastGainIndex = int32(1)
		(*SKP_Silk_decoder_state)(unsafe.Pointer(psDec)).Fprev_sigtype = 0
		(*SKP_Silk_decoder_state)(unsafe.Pointer(psDec)).Ffirst_frame_after_reset = int32(1)
		if fs_kHz == int32(24) {
			(*SKP_Silk_decoder_state)(unsafe.Pointer(psDec)).FHP_A = uintptr(unsafe.Pointer(&SKP_Silk_Dec_A_HP_24))
			(*SKP_Silk_decoder_state)(unsafe.Pointer(psDec)).FHP_B = uintptr(unsafe.Pointer(&SKP_Silk_Dec_B_HP_24))
		} else {
			if fs_kHz == int32(16) {
				(*SKP_Silk_decoder_state)(unsafe.Pointer(psDec)).FHP_A = uintptr(unsafe.Pointer(&SKP_Silk_Dec_A_HP_16))
				(*SKP_Silk_decoder_state)(unsafe.Pointer(psDec)).FHP_B = uintptr(unsafe.Pointer(&SKP_Silk_Dec_B_HP_16))
			} else {
				if fs_kHz == int32(12) {
					(*SKP_Silk_decoder_state)(unsafe.Pointer(psDec)).FHP_A = uintptr(unsafe.Pointer(&SKP_Silk_Dec_A_HP_12))
					(*SKP_Silk_decoder_state)(unsafe.Pointer(psDec)).FHP_B = uintptr(unsafe.Pointer(&SKP_Silk_Dec_B_HP_12))
				} else {
					if fs_kHz == int32(8) {
						(*SKP_Silk_decoder_state)(unsafe.Pointer(psDec)).FHP_A = uintptr(unsafe.Pointer(&SKP_Silk_Dec_A_HP_8))
						(*SKP_Silk_decoder_state)(unsafe.Pointer(psDec)).FHP_B = uintptr(unsafe.Pointer(&SKP_Silk_Dec_B_HP_8))
					} else {
						/* unsupported sampling rate */
					}
				}
			}
		}
	}
	/* Check that settings are valid */
}

func SKP_Silk_detect_SWB_input(tls *libc.TLS, psSWBdetect uintptr, samplesIn uintptr, nSamplesIn int32) {
	bp := tls.Alloc(976)
	defer tls.Free(976)
	var HP_8_kHz_len, i, v1, v2, v3, v5 int32
	var _ /* energy_32 at bp+964 */ int32
	var _ /* in_HP_8_kHz at bp+4 */ [480]int16
	var _ /* shift at bp+0 */ int32
	_, _, _, _, _, _ = HP_8_kHz_len, i, v1, v2, v3, v5
	/* High pass filter with cutoff at 8 khz */
	v1 = nSamplesIn
	v2 = libc.Int32FromInt32(FRAME_LENGTH_MS) * libc.Int32FromInt32(MAX_FS_KHZ)
	if v1 < v2 {
		v5 = v1
	} else {
		v5 = v2
	}
	v3 = v5
	goto _4
_4:
	HP_8_kHz_len = v3
	v1 = HP_8_kHz_len
	v2 = 0
	if v1 > v2 {
		v5 = v1
	} else {
		v5 = v2
	}
	v3 = v5
	goto _9
_9:
	HP_8_kHz_len = v3
	/* Cutoff around 9 khz */
	/* A = conv(conv([8192,14613, 6868], [8192,12883, 7337]), [8192,11586, 7911]); */
	/* B = conv(conv([575, -948, 575], [575, -221, 575]), [575, 104, 575]); */
	SKP_Silk_biquad(tls, samplesIn, uintptr(unsafe.Pointer(&SKP_Silk_SWB_detect_B_HP_Q13)), uintptr(unsafe.Pointer(&SKP_Silk_SWB_detect_A_HP_Q13)), psSWBdetect, bp+4, HP_8_kHz_len)
	i = int32(1)
	for {
		if !(i < int32(NB_SOS)) {
			break
		}
		SKP_Silk_biquad(tls, bp+4, uintptr(unsafe.Pointer(&SKP_Silk_SWB_detect_B_HP_Q13))+uintptr(i)*6, uintptr(unsafe.Pointer(&SKP_Silk_SWB_detect_A_HP_Q13))+uintptr(i)*4, psSWBdetect+uintptr(i)*8, bp+4, HP_8_kHz_len)
		goto _11
	_11:
		;
		i = i + 1
	}
	/* Calculate energy in HP signal */
	SKP_Silk_sum_sqr_shift(tls, bp+964, bp, bp+4, HP_8_kHz_len)
	/* Count concecutive samples above threshold, after adjusting threshold for number of input samples and shift */
	if *(*int32)(unsafe.Pointer(bp + 964)) > int32(int16(libc.Int32FromInt32(HP_8_KHZ_THRES)))*int32(int16(HP_8_kHz_len))>>*(*int32)(unsafe.Pointer(bp)) {
		*(*int32)(unsafe.Pointer(psSWBdetect + 24)) += nSamplesIn
		if (*SKP_Silk_detect_SWB_state)(unsafe.Pointer(psSWBdetect)).FConsecSmplsAboveThres > libc.Int32FromInt32(480)*libc.Int32FromInt32(15) {
			(*SKP_Silk_detect_SWB_state)(unsafe.Pointer(psSWBdetect)).FSWB_detected = int32(1)
		}
	} else {
		*(*int32)(unsafe.Pointer(psSWBdetect + 24)) -= nSamplesIn
		if (*SKP_Silk_detect_SWB_state)(unsafe.Pointer(psSWBdetect)).FConsecSmplsAboveThres > 0 {
			v1 = (*SKP_Silk_detect_SWB_state)(unsafe.Pointer(psSWBdetect)).FConsecSmplsAboveThres
		} else {
			v1 = 0
		}
		(*SKP_Silk_detect_SWB_state)(unsafe.Pointer(psSWBdetect)).FConsecSmplsAboveThres = v1
	}
	/* If sufficient speech activity and no SWB detected, we detect the signal as being WB */
	if (*SKP_Silk_detect_SWB_state)(unsafe.Pointer(psSWBdetect)).FActiveSpeech_ms > int32(WB_DETECT_ACTIVE_SPEECH_MS_THRES) && (*SKP_Silk_detect_SWB_state)(unsafe.Pointer(psSWBdetect)).FSWB_detected == 0 {
		(*SKP_Silk_detect_SWB_state)(unsafe.Pointer(psSWBdetect)).FWB_detected = int32(1)
	}
}

